The app accepts no body parsing middleware, which means `POST`/`PUT` routes added later would silently receive `undefined` bodies — a common source of bugs and injection opportunities.

### 2. 🔴 No Security Headers
There are no HTTP security headers set (e.g., `X-Content-Type-Options`, `X-Frame-Options`, `Content-Security-Policy`). Express exposes `X-Powered-By: Express` by default, advertising your stack to attackers.

### 3. 🟠 No Rate Limiting
The `/users` endpoint is open to abuse — brute force, scraping, or DoS attacks with no throttling in place.

### 4. 🟠 No Centralized Error Handling
Unhandled promise rejections or runtime errors will crash the process or leak stack traces to clients.

### 5. 🟡 Static Data Leakage Risk
The `/users` endpoint currently returns hardcoded data, but if this is ever wired to a real data source, there's no pagination, filtering validation, or output sanitization.

### 6. 🟡 No Request Logging
No audit trail for incoming requests makes incident investigation impossible.

---

## Suggested Improvements

```js
'use strict';

const express = require('express');
const helmet = require('helmet');         // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();

// ── Security Headers ────────────────────────────────────────────────────────
// Disables X-Powered-By, sets X-Content-Type-Options, X-Frame-Options, etc.
app.use(helmet());

// ── Body Parsing ─────────────────────────────────────────────────────────────
// Strict size limits prevent payload-based DoS attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// ── Rate Limiting ────────────────────────────────────────────────────────────
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // max 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// ── Routes ───────────────────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  // Avoid leaking internal timestamps in production if not needed
  res.json({ status: 'ok' });
});

app.get('/users', (req, res) => {
  // Input validation example: safe pagination params
  const page = Math.max(1, parseInt(req.query.page, 10) || 1);
  const limit = Math.min(100, Math.max(1, parseInt(req.query.limit, 10) || 20));

  // NOTE: Replace with real DB query — never interpolate query params directly into SQL/NoSQL
  const allUsers = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  const start = (page - 1) * limit;
  res.json({ data: allUsers.slice(start, start + limit), page, limit });
});

// ── 404 Handler ───────────────────────────────────────────────────────────────
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ── Centralized Error Handler ─────────────────────────────────────────────────
// Must have 4 arguments for Express to recognise it as an error handler
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Never leak stack traces or internal messages to clients
  console.error(`[${new Date().toISOString()}] Error:`, err);

  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: status < 500 ? err.message : 'Internal server error',
  });
});

// ── Process-level Safety Nets ─────────────────────────────────────────────────
process.on('unhandledRejection', (reason) => {
  console.error('Unhandled promise rejection:', reason);
  // In production: alert + graceful shutdown
});

process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  process.exit(1); // Fail fast — let your process manager restart
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;
```

